/// 1000-CONTROL
fn p_1000_control(state: &mut ProgramState) {
    state.queue_info.input_queue_name = FixedString::spaces();
    state.queue_info.qmgr_name = FixedString::spaces();
    state.queue_message = FixedString::spaces();
    state.mq_err_display = Default::default();
    p_2100_open_error_queue(state);
    // EXEC CICS RETRIEVE 
    state.cics.execute("RETRIEVE", &[("INTO", Some("_unknown")), ("MQTM", Some("_unknown")), ("RESP", Some("_unknown")), ("WS-CICS-RESP1-CD", Some("_unknown")), ("RESP2", Some("_unknown")), ("WS-CICS-RESP2-CD", Some("_unknown"))]);
    // SKIP: unresolved condition
    p_2300_open_input_queue(state);
    p_2400_open_output_queue(state);
    p_3000_get_request(state);
    while !(state.ws_mq_msg_flag == "Y") {
        p_4000_main_process(state);
    }
    p_8000_termination(state);
}

/// 2300-OPEN-INPUT-QUEUE
fn p_2300_open_input_queue(state: &mut ProgramState) {
    state.mq_object_descriptor.mqod_objectqmgrname = FixedString::spaces();
    state.mq_object_descriptor.mqod_objectname = FixedString::copy_from(&state.queue_info.input_queue_name);
    state.mq_options = (state.mq_constants.mqoo_input_shared + state.mq_constants.mqoo_save_all_context + state.mq_constants.mqoo_fail_if_quiescing) as i32;
    {
        let mut _p1 = (state.qmgr_handle_conn).clone();
        let mut _p2 = (state.mq_object_descriptor).clone();
        let mut _p3 = (state.mq_options).clone();
        let mut _p4 = (state.mq_hobj).clone();
        let mut _p5 = (state.mq_condition_code).clone();
        let mut _p6 = (state.mq_reason_code).clone();
        mqopen(&mut _p1, &mut _p2, &mut _p3, &mut _p4, &mut _p5, &mut _p6);
        state.qmgr_handle_conn = _p1;
        state.mq_object_descriptor = _p2;
        state.mq_options = _p3;
        state.mq_hobj = _p4;
        state.mq_condition_code = _p5;
        state.mq_reason_code = _p6;
    }
    match state.mq_condition_code {
        _ => {
            state.mq_err_display.mq_appl_condition_code = state.mq_condition_code as u32;
            state.mq_err_display.mq_appl_reason_code = state.mq_reason_code as u32;
            state.input_queue_handle = state.mq_hobj as i32;
            state.ws_reply_queue_sts = "Y".into();
        }
        _ => {
            state.mq_err_display.mq_appl_condition_code = state.mq_condition_code as u32;
            state.mq_err_display.mq_appl_reason_code = state.mq_reason_code as u32;
            state.mq_err_display.mq_appl_queue_name = FixedString::copy_from(&state.queue_info.input_queue_name);
            state.mq_err_display.mq_appl_return_message = "INP MQOPEN ERR".into();
            p_9000_error(state);
            p_8000_termination(state);
        }
    }
}

