/// 8000-TERMINATION
fn p_8000_termination(state: &mut ProgramState) {
    if state.ws_reply_queue_sts == "Y" {
        p_5000_close_input_queue(state);
    }
    if state.ws_resp_queue_sts == "Y" {
        p_5100_close_output_queue(state);
    }
    if state.ws_err_queue_sts == "Y" {
        p_5200_close_error_queue(state);
    }
    // EXEC CICS RETURN 
    state.cics.execute("RETURN", &[]);
    return;
}

